mapper.select:
select m.id shopid,c.id cid,c.p_id,c.user_id,m.is_open,m.logo,m.name as mch_name,m.collection_num from lkt_user_collection as c left join lkt_mch as m on c.mch_id = m.id
c.add_time ${add_time_sort},
limit #{pageStart},#{pageEnd}

SELECT c.id, c.p_id, a.product_title, a.mch_id,a.status,a.num,a.s_type,a.recycle,a.imgurl FROM lkt_user_collection AS c
     LEFT JOIN lkt_product_list AS a ON c.p_id = a.id
     WHERE a.store_id = #{store_id} AND c.type = 1 AND c.user_id = #{user_id}
 and a.commodity_type=#{commodity_type} 
 and a.product_title like concat('%',#{mchNameOrProName},'%')
     ORDER BY c.add_time DESC,a.recycle DESC
